('foundation', 'tenses-advanced', 'intermediate', 'I _____ working at 5 PM tomorrow.', '["will work", "will be working", "will worked", "will be work"]', 1, 'Future continuous: will be + V-ing. Shows action in progress at specific future time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'She _____ sleeping when you arrive.', '["will sleep", "will be sleeping", "will slept", "will be sleep"]', 1, 'Future continuous: will be + V-ing. Action in progress when another action happens.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'They _____ studying all night.', '["will study", "will be studying", "will studied", "will be study"]', 1, 'Future continuous: will be + V-ing. Shows duration in future.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'At 10 AM, he _____ in a meeting.', '["will be sitting", "will sit", "will sat", "will be sit"]', 0, 'Future continuous: will be + V-ing for specific future time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'This time next week, we _____ to Mumbai.', '["will travel", "will be traveling", "will traveled", "will be travel"]', 1, 'Future continuous: will be + V-ing. Specific future moment.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'I _____ my exam tomorrow morning.', '["will take", "will be taking", "will took", "will be take"]', 1, 'Future continuous: will be + V-ing. Action in progress during that period.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'She _____ dinner when we arrive.', '["will cook", "will be cooking", "will cooked", "will be cook"]', 1, 'Future continuous: will be + V-ing + when. Background action.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'They _____ at the airport at 6 PM.', '["will wait", "will be waiting", "will waited", "will be wait"]', 1, 'Future continuous: will be + V-ing. Specific future time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'At noon, I _____ lunch.', '["will have", "will be having", "will had", "will be have"]', 1, 'Future continuous: will be + V-ing. Action in progress at exact moment.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'Next month, we _____ our new office.', '["will use", "will be using", "will used", "will be use"]', 1, 'Future continuous: will be + V-ing. Extended future period.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'I _____ you tomorrow at 3 PM.', '["will call", "will be calling", "will called", "will be call"]', 1, 'Future continuous: will be + V-ing. Polite/softer future action.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'She _____ TV all evening.', '["will watch", "will be watching", "will watched", "will be watch"]', 1, 'Future continuous: will be + V-ing. Duration throughout period.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'They _____ here for two hours.', '["will wait", "will be waiting", "will waited", "will be wait"]', 1, 'Future continuous: will be + V-ing + duration. Extended time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'At midnight, he _____ home.', '["will drive", "will be driving", "will drove", "will be drive"]', 1, 'Future continuous: will be + V-ing. Action at specific time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'This time tomorrow, I _____ on a beach.', '["will relax", "will be relaxing", "will relaxed", "will be relax"]', 1, 'Future continuous: will be + V-ing. Exact future moment.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'We _____ the project next week.', '["will complete", "will be completing", "will completed", "will be complete"]', 1, 'Future continuous: will be + V-ing. Work in progress during period.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'She _____ for her exam all day.', '["will prepare", "will be preparing", "will prepared", "will be prepare"]', 1, 'Future continuous: will be + V-ing. Continuous throughout day.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'They _____ here when you call.', '["will work", "will be working", "will worked", "will be work"]', 1, 'Future continuous: will be + V-ing + when. Background action.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'At 8 AM, I _____ to work.', '["will commute", "will be commuting", "will commuted", "will be commute"]', 1, 'Future continuous: will be + V-ing. Action at specific time.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'Next year, we _____ in a new city.', '["will live", "will be living", "will lived", "will be live"]', 1, 'Future continuous: will be + V-ing. Extended period state.', 'easy'),
-- Medium (20)
('foundation', 'tenses-advanced', 'intermediate', 'What is wrong? "I will be work at 5 PM."', '["Use working instead of work", "Use worked instead of work", "Use works instead of work", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING (not base). Must use -ing form.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"This time next week, I _____ my exam."', '["will take", "will be taking", "will have taken", "will taken"]', 1, 'Future continuous: will be + V-ing. Specific future moment.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"_____ you using this room tomorrow?"', '["Will", "Will be", "Are", "Were"]', 0, 'Future continuous question: Will + subject + be + V-ing? Polite inquiry.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "They will be wait for us."', '["Use waiting instead of wait", "Use waited instead of wait", "Use waits instead of wait", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Must use -ing form.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"When you arrive, I _____ dinner."', '["will cook", "will be cooking", "will have cooked", "cooked"]', 1, 'Future continuous for background: will be + V-ing. Scene-setting.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Difference: "I will call" vs "I will be calling"', '["First = simple, second = softer/tentative", "First = softer, second = direct", "Both same", "Both wrong"]', 0, 'Will = direct. Will be + V-ing = softer/more polite.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Don''t call at 8 PM. I _____ dinner."', '["will have", "will be having", "will have had", "had"]', 1, 'Future continuous: will be + V-ing. Action at specific time.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "She will be go to Mumbai."', '["Use going instead of go", "Use went instead of go", "Use goes instead of go", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Must use -ing.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"At this time tomorrow, we _____ to Delhi."', '["will fly", "will be flying", "will have flown", "flew"]', 1, 'Future continuous: will be + V-ing. Specific future moment.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "I will be worked from home."', '["Use working instead of worked", "Use work instead of worked", "Use works instead of worked", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING (not V3). Must use -ing.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Will you help?" vs "Will you be helping?"', '["First = request, second = asking plans", "First = plans, second = request", "Both same", "Both wrong"]', 0, 'Will = direct request. Will be + V-ing = asking about plans.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"When you wake up, I _____ breakfast."', '["will make", "will be making", "will have made", "made"]', 1, 'Future continuous for background: will be + V-ing. Scene-setting.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "Will she be arrives at 5 PM?"', '["Use arriving instead of arrives", "Use arrived instead of arrives", "Use arrive instead of arrives", "Nothing wrong"]', 0, 'Future continuous question: Will + subject + be + V-ING? Must use -ing.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Don''t disturb me tomorrow. I _____ for exam."', '["will study", "will be studying", "will have studied", "studied"]', 1, 'Future continuous: will be + V-ing. Extended time action.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: She / meeting / be / will / attending / PM / at / 3', '["She will be attending meeting at 3 PM", "She will be meeting attending at 3 PM", "At 3 PM she will be attending meeting", "She attending will be meeting at 3 PM"]', 0, 'Pattern: Subject + will be + V-ing + object + time. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: all / studying / be / will / They / night', '["They will be studying all night", "They will be all night studying", "All night they will be studying", "They studying will be all night"]', 0, 'Pattern: Subject + will be + V-ing + duration. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: tomorrow / working / be / will / We / morning', '["We will be working tomorrow morning", "We will be tomorrow morning working", "Tomorrow morning we will be working", "We working will be tomorrow morning"]', 0, 'Pattern: Subject + will be + V-ing + time. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "We will going to the party."', '["Use be going OR just will go", "Use went instead of going", "Use goes instead of going", "Nothing wrong"]', 0, 'Mixed forms! Use "will be going" (continuous) OR "will go" (simple). Don''t mix.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"By 5 PM, I _____ for three hours."', '["will work", "will be working", "will have been working", "worked"]', 2, 'Duration by specific time = future perfect continuous (not simple continuous).', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Next month, company _____ the results."', '["will announce", "will be announcing", "will announced", "will be announce"]', 1, 'Future continuous: will be + V-ing. Extended future period.', 'medium'),
-- Hard (11)
('foundation', 'tenses-advanced', 'intermediate', 'Subtle: "I will work" vs "I will be working" in plans', '["First = definite, second = tentative", "First = tentative, second = definite", "Both same", "Both wrong"]', 0, 'Will = definite decision. Will be + V-ing = softer/less committed.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Polite inquiry: "Will you attend?" vs "Will you be attending?"', '["Second is more polite", "First is more polite", "Both equally polite", "Neither polite"]', 0, 'Future continuous = more polite inquiry about plans (less direct).', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "This time next year, I will be graduated."', '["Use will have graduated", "Use will graduate", "Use will be graduating", "Nothing wrong"]', 0, 'Momentary action = future perfect (not continuous). Graduate = moment.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"By 5 PM, I _____ for three hours."', '["will work", "will be working", "will have been working", "worked"]', 2, 'Duration by time = future perfect continuous. Completion of duration.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "Next month, company will be announce results."', '["Use announcing", "Use announced", "Use announces", "Nothing wrong"]', 0, 'Future continuous: will be + V-ING. Must use -ing.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"I will meet him" vs "I will be meeting him"', '["First = simple plan, second = scheduled", "First = scheduled, second = simple", "Both same", "Both wrong"]', 0, 'Will = simple plan. Will be + V-ing = already scheduled arrangement.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"By the time you arrive, I _____ everything."', '["will finish", "will be finishing", "will have finished", "finished"]', 2, 'Completion before future time = future perfect (not continuous).', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: when / sleeping / be / will / you / She / arrive', '["She will be sleeping when you arrive", "She will be when you arrive sleeping", "When you arrive she will be sleeping", "She sleeping will be when you arrive"]', 0, 'Pattern: Subject + will be + V-ing + when + clause. Natural order.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "Will they be finish by Friday?"', '["Use finishing", "Use have finished", "Use finished", "Nothing wrong"]', 1, 'Completion by time = future perfect (not continuous). By = completion.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"I _____ you next week about decision."', '["will inform", "will be informing", "Both natural", "Neither natural"]', 2, 'Both natural! Will = direct. Will be + V-ing = softer. Context determines.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Difference: "will work" vs "will be working" emphasis', '["First = fact, second = duration emphasis", "First = duration, second = fact", "Both same", "Both wrong"]', 0, 'Will = simple fact. Will be + V-ing = emphasizes duration/ongoing nature.', 'hard'),

