('foundation', 'tenses-advanced', 'intermediate', 'She _____ working on this since Monday.', '["has worked", "has been working", "is working", "worked"]', 1, 'Present perfect continuous: has been + V-ing. Since Monday = starting point.', 'easy'),
('foundation', 'tenses-advanced', 'intermediate', 'They _____ arguing all morning.', '["have argued", "have been arguing", "are arguing", "argued"]', 1, 'Present perfect continuous: have been + V-ing. Duration "all morning".', 'easy'),
