-- Medium (20)
('foundation', 'tenses-advanced', 'intermediate', 'Difference: "worked for 5 years" vs "been working for 5 years"', '["First = neutral, second = temporary feel", "First = temporary, second = neutral", "Both same", "Both wrong"]', 0, 'Present perfect = neutral. Present perfect continuous = temporary/emphasizes duration.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "She has been go to gym lately."', '["Use going", "Use went", "Use goes", "Nothing wrong"]', 0, 'Present perfect continuous: has been + V-ING. Must use -ing form.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"You look tired. What _____?"', '["have you done", "have you been doing", "are you doing", "did you do"]', 1, 'Recent activity causing present result. Asking about activity.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "They has been studying all day."', '["Use have", "Use had", "Use are", "Nothing wrong"]', 0, 'Subject-verb agreement: They = have (not has). Plural = have.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"My hands are dirty. I _____ in garden."', '["worked", "have worked", "have been working", "am working"]', 2, 'Recent activity with present evidence. Explains dirty hands.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "I have been studied for 2 hours."', '["Use studying", "Use study", "Use studies", "Nothing wrong"]', 0, 'Present perfect continuous: have been + V-ING (not V3). Must use -ing.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"How long _____ English?"', '["do you learn", "have you learned", "have you been learning", "are you learning"]', 2, 'Duration question = present perfect continuous. Ongoing duration.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Difference: "has rained" vs "has been raining"', '["First = stopped, second = just stopped/still", "First = still, second = stopped", "Both same", "Both wrong"]', 0, 'Perfect = completed. Perfect continuous = recently completed or ongoing.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "He have been working hard."', '["Use has", "Use had", "Use is", "Nothing wrong"]', 0, 'Subject-verb agreement: He = has (not have). Singular = has.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Why are you happy? What _____?"', '["happened", "has happened", "has been happening", "happens"]', 1, 'Recent event causing present state = present perfect (not continuous).', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "We been working on this project."', '["Add have", "Add has", "Add are", "Nothing wrong"]', 0, 'Missing auxiliary! Need have/has. Must have auxiliary verb.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"I''m exhausted. I _____ all day."', '["worked", "have worked", "have been working", "am working"]', 2, 'Recent continuous activity causing exhaustion. Explains present state.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "They has been been waiting."', '["Remove been AND use have", "Remove been", "Use have", "Nothing wrong"]', 0, 'Two errors: Double "been" + wrong auxiliary. They = have, one "been".', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', '"Your eyes are red. _____ crying?"', '["Did you cry", "Have you cried", "Have you been crying", "Are you crying"]', 2, 'Recent activity with present evidence. Explains red eyes.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: for / been / working / have / hours / I / three', '["I have been working for three hours", "I have been for three hours working", "For three hours I have been working", "I working have been for three hours"]', 0, 'Pattern: Subject + have been + V-ing + for + duration. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: morning / been / waiting / has / She / since', '["She has been waiting since morning", "She has been since morning waiting", "Since morning she has been waiting", "She waiting has been since morning"]', 0, 'Pattern: Subject + has been + V-ing + since + time. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: lately / been / feeling / have / tired / You', '["You have been feeling tired lately", "You have been lately feeling tired", "Lately you have been feeling tired", "You feeling have been tired lately"]', 0, 'Pattern: Subject + have been + V-ing + adjective + time. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: weeks / been / reading / has / book / for / She / this', '["She has been reading this book for weeks", "She has been this book reading for weeks", "For weeks she has been reading this book", "She reading has been this book for weeks"]', 0, 'Pattern: Subject + has been + V-ing + object + for + duration. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: lately / watching / been / have / show / We / this', '["We have been watching this show lately", "We have been this show watching lately", "Lately we have been watching this show", "We watching have been this show lately"]', 0, 'Pattern: Subject + have been + V-ing + object + time. Natural order.', 'medium'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: month / working / been / has / on / He / project / all / this', '["He has been working on this project all month", "He has been on this project working all month", "All month he has been working on this project", "He working has been on this project all month"]', 0, 'Pattern: Subject + has been + V-ing + on + object + duration. Natural order.', 'medium'),
-- Hard (11)
('foundation', 'tenses-advanced', 'intermediate', 'Stative verb: "I have known" vs "I have been knowing"', '["First correct, second wrong", "First wrong, second correct", "Both correct", "Both wrong"]', 0, 'Stative verbs don''t use continuous! Know = state (not action). No continuous.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Subtle: "lived in Mumbai" vs "been living in Mumbai"', '["First = permanent, second = temporary feel", "First = temporary, second = permanent", "Both same", "Both wrong"]', 0, 'Perfect = neutral/permanent. Perfect continuous = temporary feeling. Nuance!', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "Each student have been working hard."', '["Use has", "Use had", "Use is", "Nothing wrong"]', 0, 'Subject-verb agreement: "Each student" = singular = has. Each = singular.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"The road is wet. It _____."', '["rained", "has rained", "has been raining", "is raining"]', 2, 'Recent activity with present evidence. Explains wet road (just stopped).', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "I have been finish my work."', '["Use finishing", "Use finished", "Use finishes", "Nothing wrong"]', 0, 'Present perfect continuous: have been + V-ING. Must use -ing form.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"How many books read?" vs "What been reading?"', '["First = count, second = activity", "First = activity, second = count", "Both same", "Both wrong"]', 0, 'Perfect = completed count. Perfect continuous = recent activity. Different focus!', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Error: "She has been win many awards."', '["Use winning", "Use won", "Use wins", "Nothing wrong"]', 1, 'Repeated achievements better with perfect (not continuous). Completed achievements = perfect.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', '"I''m tired because I _____ all day."', '["worked", "have worked", "have been working", "am working"]', 2, 'Recent continuous activity causing tiredness. Explains current state.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: exams / weeks / been / have / preparing / for / They / three / for', '["They have been preparing for exams for three weeks", "They have been for exams preparing for three weeks", "For three weeks they have been preparing for exams", "They preparing have been for exams for three weeks"]', 0, 'Pattern: Subject + have been + V-ing + for + object + for + duration. Natural order.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: morning / waiting / been / since / for / have / you / I', '["I have been waiting for you since morning", "I have been for you waiting since morning", "Since morning I have been waiting for you", "I waiting have been for you since morning"]', 0, 'Pattern: Subject + have been + V-ing + for + object + since + time. Natural order.', 'hard'),
('foundation', 'tenses-advanced', 'intermediate', 'Arrange: lately / improving / been / team / The / has', '["The team has been improving lately", "The team has been lately improving", "Lately the team has been improving", "The improving has been team lately"]', 0, 'Pattern: Subject + has been + V-ing + time. Natural order.', 'hard');

